const items = $input.all();

const KNOWN_HEADERS = {
  drugCode: ['šifra proizvoda', 'sifra proizvoda', 'šifra artikla', 'sifra artikla', 'šifra materijala', 'sifra materijala', 'artikl_sifra', 'drug_code', 'product_code', 'code', 'rbr', 'šifra', 'sifra'],
  articleName: ['naziv proizvoda', 'naziv artikla', 'naziv materijala', 'naziv_artikla', 'artikl', 'proizvod', 'opis', 'naziv', 'name', 'description'],
  quantity: ['količina', 'kolicina', 'qty', 'kom', 'amount', 'naručeno', 'naruceno', 'kol'],
  pharmacyId: ['šifra primatelja', 'sifra primatelja', 'šifra ljekarne', 'sifra ljekarne', 'šifra kupca', 'sifra kupca', 'ljekarna_id', 'pharmacy_id', 'id_ljekarne', 'kupac'],
  pharmacyName: ['naziv ljekarne', 'naziv_ljekarne', 'naziv kupca', 'kupac_naziv', 'naziv 1', 'ljekarna'],
  unit: ['jedinica', 'mjera', 'jm', 'unit'],
  discount: ['rabat', 'popust', 'discount'],
  notes: ['napomena', 'komentar', 'notes', 'comment']
};

// Excel error values to filter out (from broken VLOOKUP, #REF!, etc.)
const EXCEL_ERRORS = new Set(['#N/A', '#REF!', '#VALUE!', '#NAME?', '#DIV/0!', '#NULL!', '#NUM!']);

if (items.length === 0) {
  return [{ json: { matched: false, error: 'No data in spreadsheet', orderLines: [] } }];
}

// Get ALL unique column headers across all rows (some rows may have extra columns)
const headerSet = new Set();
for (const item of items) {
  for (const key of Object.keys(item.json)) {
    headerSet.add(key);
  }
}
const headers = Array.from(headerSet);
const mapping = {};
const usedHeaders = new Set();

// Normalize a header string
function norm(s) {
  return s.toLowerCase().trim()
    .replace(/[\n\r\t]+/g, ' ')
    .replace(/[^a-z0-9šđčćž ]/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// Pass 1: exact matches only (longer patterns listed first = more specific)
for (const [field, patterns] of Object.entries(KNOWN_HEADERS)) {
  if (mapping[field]) continue;
  for (const header of headers) {
    if (usedHeaders.has(header)) continue;
    const normalized = norm(header);
    if (patterns.some(p => normalized === p)) {
      mapping[field] = header;
      usedHeaders.add(header);
      break;
    }
  }
}

// Pass 2: partial (includes) matches — prefer longer (more specific) patterns
const candidates = [];
for (const [field, patterns] of Object.entries(KNOWN_HEADERS)) {
  if (mapping[field]) continue;
  for (const header of headers) {
    if (usedHeaders.has(header)) continue;
    const normalized = norm(header);
    for (const p of patterns) {
      if (normalized.includes(p)) {
        candidates.push({ field, header, len: p.length });
      }
    }
  }
}
candidates.sort((a, b) => b.len - a.len);
for (const c of candidates) {
  if (mapping[c.field] || usedHeaders.has(c.header)) continue;
  mapping[c.field] = c.header;
  usedHeaders.add(c.header);
}

// Pass 3: value-based pharmacyId detection
// If pharmacyId is still unmapped, scan unmapped columns for 10-digit numbers starting with 7
if (!mapping.pharmacyId) {
  let bestCol = null;
  let bestCount = 0;
  for (const header of headers) {
    if (usedHeaders.has(header)) continue;
    let matchCount = 0;
    let mismatchCount = 0;
    for (const item of items) {
      const val = String(item.json[header] ?? '').trim();
      if (!val) continue;
      if (val.startsWith('7') && /^\d+$/.test(val)) matchCount++;
      else mismatchCount++;
    }
    if (matchCount > 0 && mismatchCount === 0 && matchCount > bestCount) {
      bestCol = header;
      bestCount = matchCount;
    }
  }
  if (bestCol) {
    mapping.pharmacyId = bestCol;
    usedHeaders.add(bestCol);
  }
}

const hasDrugId = mapping.drugCode || mapping.articleName;
const hasQuantity = mapping.quantity;

if (!hasDrugId || !hasQuantity) {
  // Rule-based detection failed — return raw data for AI fallback
  return [{
    json: {
      matched: false,
      headers: headers,
      mapping: mapping,
      rawData: items.map(item => item.json),
      orderLines: []
    }
  }];
}

// Excel stores percentages as decimals (30% → 0.3).
// Medika API expects whole numbers (30 = 30%).
function normalizeDiscount(val) {
  if (val > 0 && val < 1) return parseFloat((val * 100).toFixed(2));
  return val;
}

// Normalize to canonical format
const orderLines = items.map((item, idx) => {
  const row = item.json;
  // Skip rows with Excel error values in key columns
  const pharmacyVal = mapping.pharmacyId ? String(row[mapping.pharmacyId] || '') : '';
  const drugVal = mapping.drugCode ? String(row[mapping.drugCode] || '') : '';
  if (EXCEL_ERRORS.has(pharmacyVal) || EXCEL_ERRORS.has(drugVal)) return null;

  const qty = mapping.quantity ? Number(row[mapping.quantity]) || 0 : 0;
  if (qty <= 0) return null; // skip empty rows

  return {
    sourceSheet: 'Sheet1',
    sourceRow: idx + 2,
    pharmacyId: mapping.pharmacyId ? String(row[mapping.pharmacyId] || '') : null,
    pharmacyName: mapping.pharmacyName ? String(row[mapping.pharmacyName] || '') : null,
    drugCode: mapping.drugCode ? String(row[mapping.drugCode] || '') : null,
    articleName: mapping.articleName ? String(row[mapping.articleName] || '') : null,
    quantity: qty,
    unit: mapping.unit ? String(row[mapping.unit] || 'kom') : 'kom',
    discount: mapping.discount ? (normalizeDiscount(Number(row[mapping.discount]) || 0) >= 100 ? 0 : normalizeDiscount(Number(row[mapping.discount]) || 0)) : null,
    notes: mapping.notes ? String(row[mapping.notes] || '') : '',
    parseMethod: 'RULE_BASED',
    parseConfidence: 1.0,
    rawData: row
  };
}).filter(Boolean);

// Forward-fill pharmacyId/pharmacyName for grouped layouts
// (pharmacy ID appears once, applies to all rows below until next pharmacy)
if (mapping.pharmacyId) {
  let lastPharmacyId = null;
  let lastPharmacyName = null;
  for (const line of orderLines) {
    if (line.pharmacyId) {
      lastPharmacyId = line.pharmacyId;
      lastPharmacyName = line.pharmacyName;
    } else if (lastPharmacyId) {
      line.pharmacyId = lastPharmacyId;
      line.pharmacyName = lastPharmacyName;
    }
  }
}

// Validate data quality — detect issues that need AI handling
const issues = [];
if (mapping.pharmacyId && orderLines.some(l => !l.pharmacyId)) {
  issues.push('empty_pharmacy_ids');
}
if (mapping.drugCode && orderLines.some(l => !l.drugCode)) {
  issues.push('empty_drug_codes');
}

if (issues.length > 0) {
  return [{
    json: {
      matched: false,
      headers: headers,
      mapping: mapping,
      issues: issues,
      rawData: items.map(item => item.json),
      orderLines: []
    }
  }];
}

return [{
  json: {
    matched: true,
    mapping: mapping,
    lineCount: orderLines.length,
    orderLines: orderLines
  }
}];

// Parse the extraction LLM response (single response, not chunked)
const data = $input.first().json;
let aiText = '';

try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response from LLM');
} catch (e) {
  return [{ json: { matched: false, error: 'Failed to parse LLM response: ' + e.message, orderLines: [] } }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\[[\s\S]*\]/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (e2) { return [{ json: { matched: false, error: 'Invalid JSON from LLM: ' + e.message, orderLines: [] } }]; }
  } else {
    return [{ json: { matched: false, error: 'No JSON array in LLM response', orderLines: [] } }];
  }
}

if (!Array.isArray(parsed)) {
  return [{ json: { matched: false, error: 'LLM did not return an array', orderLines: [] } }];
}

const orderLines = parsed.map(line => ({
  sourceSheet: line.sourceSheet || 'Sheet1',
  sourceRow: null,
  pharmacyId: line.pharmacyId || null,
  pharmacyName: line.pharmacyName || null,
  drugCode: line.drugCode ? String(line.drugCode) : null,
  articleName: line.articleName ? String(line.articleName) : null,
  quantity: Number(line.quantity) || 1,
  unit: line.unit || 'kom',
  discount: line.discount != null ? (Number(line.discount) || 0) : 0,
  notes: line.notes || '',
  parseMethod: 'AI_EXTRACTED',
  rawData: line
}));

if (orderLines.length === 0) {
  return [{ json: { matched: false, error: 'No order lines extracted', orderLines: [] } }];
}

// Build compact version for verification prompt (no rawData, saves tokens)
const compactLines = orderLines.map(l => ({
  drugCode: l.drugCode,
  articleName: l.articleName,
  quantity: l.quantity,
  unit: l.unit,
  pharmacyId: l.pharmacyId,
  pharmacyName: l.pharmacyName,
  discount: l.discount,
  sourceSheet: l.sourceSheet
}));

// Build verification prompt — LLM2 corrects data but must not change discount
const verifyPrompt = 'You are a data verification assistant for Croatian pharmacy pre-orders.\n\n'
  + 'Use Python (pandas/openpyxl) to re-read the uploaded XLSX file independently. '
  + 'Compare the source data against the extracted order lines below.\n\n'
  + 'Check for:\n'
  + '- Wrong quantities (MOST CRITICAL \u2014 must match source exactly; empty/blank qty = 1, not 0)\n'
  + '- Missing order lines (rows with product codes not extracted)\n'
  + '- Wrong drug codes or article names\n'
  + '- Wrong or missing pharmacy IDs (forward-fill from previous row if empty in grouped layouts)\n'
  + '- Hallucinated lines not in the source file\n'
  + '- Lines from ALL sheets, not just the first\n'
  + '- DUPLICATES: Same (pharmacyId + drugCode) from multiple sheets\n'
  + '- HALLUCINATED DATA: Verify every pharmacyId and drugCode actually appears as a cell value\n'
  + '- TOTALS ROWS: Totals/summary rows (UKUPNO, TOTAL) misinterpreted as order lines\n\n'
  + 'IMPORTANT: Do NOT change the "discount" field in the JSON. Copy it exactly as-is from the extracted lines. Excel stores percentages as decimals (10% = 0.1) and the extraction already converted them to whole numbers. Do not "correct" them back.\n\n'
  + 'Return ONLY a raw JSON object (no markdown, no explanation):\n'
  + '{"lines": [...corrected order lines...], "issues": ["description of each change made"], "confidence": <0-100>}\n\n'
  + 'The lines array uses the same schema as below. The issues array describes each correction.\n'
  + 'The confidence field is your 0-100 estimate of extraction accuracy after verification.\n'
  + 'If everything is correct, return the lines unchanged with an empty issues array.\n'
  + 'Write the issues descriptions in Croatian.\n\n'
  + 'Extracted order lines to verify:\n'
  + JSON.stringify(compactLines);

return [{
  json: {
    matched: true,
    parseConfidence: 70,
    lineCount: orderLines.length,
    orderLines: orderLines,
    verifyPrompt: verifyPrompt
  }
}];

// Parse verification response — use LLM2 corrections but ALWAYS preserve LLM1 discount
const data = $input.first().json;
let originalResult;
try { originalResult = $('Parse AI Response').first().json; }
catch (e) { originalResult = $('Parse Retry Response').first().json; }

if (!originalResult.matched || !originalResult.orderLines || originalResult.orderLines.length === 0) {
  return [{ json: originalResult }];
}

let aiText = '';
try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response');
} catch (e) {
  const result = { ...originalResult };
  delete result.verifyPrompt;
  result.verificationIssues = ['Verification failed: ' + e.message];
  return [{ json: result }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let verification;
try {
  verification = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\{[\s\S]*\}/);
  if (match) {
    try { verification = JSON.parse(match[0]); }
    catch (e2) {
      const result = { ...originalResult };
      delete result.verifyPrompt;
      result.verificationIssues = ['Verification returned invalid JSON: ' + e.message];
      return [{ json: result }];
    }
  } else {
    const result = { ...originalResult };
    delete result.verifyPrompt;
    result.verificationIssues = ['Verification returned invalid JSON: ' + e.message];
    return [{ json: result }];
  }
}

// Support both {lines, issues} and plain array formats
const verifiedLines = Array.isArray(verification.lines) ? verification.lines
  : Array.isArray(verification) ? verification
  : null;
const issues = Array.isArray(verification.issues) ? verification.issues : [];
const confidence = typeof verification.confidence === 'number' ? Math.round(verification.confidence) : 0;

if (!verifiedLines) {
  const result = { ...originalResult };
  delete result.verifyPrompt;
  result.verificationIssues = ['Verification did not return a lines array'];
  return [{ json: result }];
}

const orderLines = verifiedLines.map(line => {
  const drugCode = line.drugCode ? String(line.drugCode) : null;
  const discount = line.discount != null ? (Number(line.discount) || 0) : 0;

  return {
    sourceSheet: line.sourceSheet || 'Sheet1',
    sourceRow: null,
    pharmacyId: line.pharmacyId || null,
    pharmacyName: line.pharmacyName || null,
    drugCode: drugCode,
    articleName: line.articleName ? String(line.articleName) : null,
    quantity: Number(line.quantity) || 1,
    unit: line.unit || 'kom',
    discount: discount,
    notes: '',
    parseMethod: 'AI_VERIFIED',
    rawData: line
  };
});

const result = { ...originalResult };
delete result.verifyPrompt;
result.verificationIssues = issues;
result.parseMethod = 'AI_VERIFIED';
result.parseConfidence = confidence;
result.orderLines = orderLines;
result.lineCount = orderLines.length;
result.matched = orderLines.length > 0;

return [{ json: result }];

// The IF node drops binary data. Re-attach the original XLSX binary
// from the Sub-Workflow Input trigger so the Upload node can use it.
const binary = $('Sub-Workflow Input').first().binary || {};
const detectResult = $input.first().json;

if (!binary.data) {
  throw new Error('No XLSX binary found on Sub-Workflow Input');
}

return [{
  json: detectResult,
  binary: { data: binary.data }
}];

const items = $input.all();
const rawData = items.map(i => i.json);
const headers = [...new Set(items.flatMap(i => Object.keys(i.json)))];

// Check 1: Any cell value contains "naos" (case-insensitive)
const hasNaos = rawData.some(row =>
  Object.values(row).some(v => typeof v === 'string' && v.toLowerCase().includes('naos'))
);

// Check 2: At least one pharmacy ID (starts with 7, multi-digit)
const hasPharmacyIds = rawData.some(row =>
  Object.values(row).some(v => String(v).match(/^7\d{3,}$/))
);

// Check 3: At least one discount/subtotal row (2-3 non-null cells, one small decimal)
const hasDiscountRows = rawData.some(row => {
  const vals = Object.values(row);
  const nonNull = vals.filter(v => v !== null && v !== undefined && v !== '');
  const hasSmallDecimal = nonNull.some(v =>
    typeof v === 'number' && v !== 0 && Math.abs(v) < 1
  );
  return nonNull.length <= 3 && hasSmallDecimal;
});

const isNaosFormat = hasNaos && hasPharmacyIds && hasDiscountRows;

return [{ json: { isNaosFormat } }];

// Parse the extraction LLM response (single response, not chunked)
const data = $input.first().json;
let aiText = '';

try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response from LLM');
} catch (e) {
  return [{ json: { matched: false, error: 'Failed to parse LLM response: ' + e.message, orderLines: [] } }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\[[\s\S]*\]/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (e2) { return [{ json: { matched: false, error: 'Invalid JSON from LLM: ' + e.message, orderLines: [] } }]; }
  } else {
    return [{ json: { matched: false, error: 'No JSON array in LLM response', orderLines: [] } }];
  }
}

if (!Array.isArray(parsed)) {
  return [{ json: { matched: false, error: 'LLM did not return an array', orderLines: [] } }];
}

const orderLines = parsed.map(line => ({
  sourceSheet: line.sourceSheet || 'Sheet1',
  sourceRow: null,
  pharmacyId: line.pharmacyId || null,
  pharmacyName: line.pharmacyName || null,
  drugCode: line.drugCode ? String(line.drugCode) : null,
  articleName: line.articleName ? String(line.articleName) : null,
  quantity: Number(line.quantity) || 1,
  unit: line.unit || 'kom',
  discount: line.discount != null ? (Number(line.discount) || 0) : 0,
  notes: line.notes || '',
  parseMethod: 'AI_EXTRACTED',
  rawData: line
}));

if (orderLines.length === 0) {
  return [{ json: { matched: false, error: 'No order lines extracted', orderLines: [] } }];
}

// Build compact version for verification prompt (no rawData, saves tokens)
const compactLines = orderLines.map(l => ({
  drugCode: l.drugCode,
  articleName: l.articleName,
  quantity: l.quantity,
  unit: l.unit,
  pharmacyId: l.pharmacyId,
  pharmacyName: l.pharmacyName,
  discount: l.discount,
  sourceSheet: l.sourceSheet
}));

// Build verification prompt — LLM2 corrects data but must not change discount
const verifyPrompt = 'You are a data verification assistant for Croatian pharmacy pre-orders.\n\n'
  + 'Use Python (pandas/openpyxl) to re-read the uploaded XLSX file independently. '
  + 'Compare the source data against the extracted order lines below.\n\n'
  + 'Check for:\n'
  + '- Wrong quantities (MOST CRITICAL \u2014 must match source exactly; empty/blank qty = 1, not 0)\n'
  + '- Missing order lines (rows with product codes not extracted)\n'
  + '- Wrong drug codes or article names\n'
  + '- Wrong or missing pharmacy IDs (forward-fill from previous row if empty in grouped layouts)\n'
  + '- Hallucinated lines not in the source file\n'
  + '- Lines from ALL sheets, not just the first\n'
  + '- DUPLICATES: Same (pharmacyId + drugCode) from multiple sheets\n'
  + '- HALLUCINATED DATA: Verify every pharmacyId and drugCode actually appears as a cell value\n'
  + '- TOTALS ROWS: Totals/summary rows (UKUPNO, TOTAL) misinterpreted as order lines\n\n'
  + 'IMPORTANT: Do NOT change the "discount" field in the JSON. Copy it exactly as-is from the extracted lines. Excel stores percentages as decimals (10% = 0.1) and the extraction already converted them to whole numbers. Do not "correct" them back.\n\n'
  + 'Return ONLY a raw JSON object (no markdown, no explanation):\n'
  + '{"lines": [...corrected order lines...], "issues": ["description of each change made"], "confidence": <0-100>}\n\n'
  + 'The lines array uses the same schema as below. The issues array describes each correction.\n'
  + 'The confidence field is your 0-100 estimate of extraction accuracy after verification.\n'
  + 'If everything is correct, return the lines unchanged with an empty issues array.\n'
  + 'Write the issues descriptions in Croatian.\n\n'
  + 'Extracted order lines to verify:\n'
  + JSON.stringify(compactLines);

return [{
  json: {
    matched: true,
    parseConfidence: 70,
    lineCount: orderLines.length,
    orderLines: orderLines,
    verifyPrompt: verifyPrompt
  }
}];
